import React, { useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";

import { useAppDispatch, useAppSelector } from "./store/hooks/reduxHooks";

import { fetchCart, removeCartItem, buyCart } from "./store/thunks/cartThunks";

function CartPage() {
  const dispatch = useAppDispatch();
  const queryClient = useQueryClient();

  const cart = useAppSelector((state) => state.cart);

  // загрузка корзины при входе на страницу
  useEffect(() => {
    dispatch(fetchCart());
  }, [dispatch]);

  // удаление товара
  const removeMutation = useMutation({
    mutationFn: removeCartItem,

    onMutate: async (id) => {
      await queryClient.cancelQueries(["cart"]);

      const prevCart = queryClient.getQueryData(["cart"]);

      queryClient.setQueryData(["cart"], (old) => {
        if (!old) return old;

        return {
          ...old,
          items: old.items.filter((i) => i.id !== id),
        };
      });

      return { prevCart };
    },

    onError: (err, id, context) => {
      queryClient.setQueryData(["cart"], context?.prevCart);
    },

    onSettled: () => {
      queryClient.invalidateQueries(["cart"]);
    },
  });

  // покупка
  const buyMutation = useMutation({
    mutationFn: buyCart,

    onSuccess: () => {
      alert("✅ Покупка сохранена!");
      queryClient.invalidateQueries(["cart"]);
    },

    onError: (error) => {
      alert("❌ Ошибка: " + error.message);
    },
  });

  // loading safety
  if (!cart) return <p>Загрузка...</p>;

  return (
    <div id="content">
      <h2>Корзина</h2>

      {/* пустая корзина */}
      {(!cart.items || cart.items.length === 0) && (
        <p>Корзина пуста</p>
      )}

      {/* список товаров */}
      {cart.items?.map((item) => (
        <div key={item.id}>
          <p>
            {item.game?.title || item.item?.title} —{" "}
            {item.game?.price || item.item?.price} ₽
          </p>

          <button
            onClick={() => removeMutation.mutate(item.id)}
          >
            Удалить
          </button>
        </div>
      ))}

      {/* итог */}
      <h3>Итого: {cart?.total ?? 0} ₽</h3>

      {/* купить */}
      <button
        id="buy_button"
        onClick={() => buyMutation.mutate()}
        disabled={buyMutation.isLoading}
      >
        Купить
      </button>
    </div>
  );
}

export default CartPage;
